// CreateSandbox creates a new sandbox session.
func (sc *SandboxController) CreateSandbox(ctx context.Context, req *CreateSandboxRequest) (*CreateSandboxResponse, error) {
	// Generate session ID
	sessionID := uuid.New().String()

	// Check for existing session with same name
	// In real implementation, query store by name

	// Calculate expiration
	sessionTimeout := req.SessionTimeout
	if sessionTimeout == 0 {
		sessionTimeout = 15 * time.Minute
	}

	maxDuration := req.MaxDuration
	if maxDuration == 0 {
		maxDuration = 8 * time.Hour
	}

	expiresAt := time.Now().Add(maxDuration)

	// Store placeholder before CR creation
	sandbox := &SandboxInfo{
		SessionID:      sessionID,
		Namespace:      req.Namespace,
		Name:           req.Name,
		Kind:           req.Kind,
		ExpiresAt:      expiresAt,
		LastActivityAt: time.Now(),
		CreatedAt:      time.Now(),
		Status:         "Pending",
		Labels:         req.Labels,
		Annotations:    req.Annotations,
	}

	if err := sc.store.StoreSandbox(ctx, sandbox); err != nil {
		return nil, fmt.Errorf("failed to store placeholder: %w", err)
	}

	// Create K8s sandbox resource
	spec := &SandboxSpec{
		Namespace:      req.Namespace,
		Name:           req.Name,
		Kind:           req.Kind,
		PodTemplate:    req.PodTemplate,
		SessionTimeout: sessionTimeout,
		MaxDuration:    maxDuration,
