				}

				// Build endpoint
				endpoint := fmt.Sprintf("http://%s", podIP)
				if len(sandbox.EntryPoints) > 0 {
					endpoint = fmt.Sprintf("%s:%d", endpoint, sandbox.EntryPoints[0].Port)
				}

				return &CreateSandboxResponse{
					SessionID:   sessionID,
					Endpoint:    endpoint,
					EntryPoints: sandbox.EntryPoints,
					Status:      "Running",
				}, nil
			}

			if status.Phase == "Failed" {
				sc.store.DeleteSandboxBySessionID(ctx, sessionID)
				return nil, fmt.Errorf("sandbox failed to start: %s", status.Message)
			}
		}
	}
}

// DeleteSandbox deletes a sandbox session.
func (sc *SandboxController) DeleteSandbox(ctx context.Context, sessionID string) error {
	// Get sandbox info
	sandbox, err := sc.store.GetSandboxBySessionID(ctx, sessionID)
	if err != nil {
		return fmt.Errorf("failed to get sandbox: %w", err)
	}

	// Delete K8s resource
	if err := sc.k8sClient.DeleteSandbox(ctx, sandbox.Namespace, sandbox.Name); err != nil {
		// Continue to delete from store even if K8s delete fails
		// Log error but don't return
	}

	// Delete from store
	if err := sc.store.DeleteSandboxBySessionID(ctx, sessionID); err != nil {
		return fmt.Errorf("failed to delete sandbox from store: %w", err)
	}

	return nil
}

// StartGarbageCollector starts the garbage collection loop.
func (sc *SandboxController) StartGarbageCollector(ctx context.Context) {
	sc.garbageCollector.Start(ctx)
}

// StopGarbageCollector stops the garbage collection loop.
func (sc *SandboxController) StopGarbageCollector() {
	sc.garbageCollector.Stop()
}

