// Package webhook provides webhook functionality for AgentCube.
// AR-017: Webhook System - Hybrid approach (middleware for auth, handler for processing)
package webhook

import (
	"bytes"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"net/http"
	"net/url"
	"time"

	"github.com/gin-gonic/gin"
	"github.com/google/uuid"
)

// Event represents a webhook event.
type Event struct {
	ID        string          `json:"id"`
	Type      string          `json:"type"`
	Timestamp time.Time       `json:"timestamp"`
	Payload   json.RawMessage `json:"payload"`
}

// EventPayload represents the payload for different event types.
type EventPayload struct {
	SandboxID string `json:"sandbox_id,omitempty"`
	SessionID string `json:"session_id,omitempty"`
	Namespace string `json:"namespace,omitempty"`
	Name      string `json:"name,omitempty"`
	Kind      string `json:"kind,omitempty"`
	Status    string `json:"status,omitempty"`
	Message   string `json:"message,omitempty"`
	Error     string `json:"error,omitempty"`
	Duration  int64  `json:"duration_ms,omitempty"`
}

// Event types
const (
	EventTypeSandboxCreated    = "sandbox.created"
	EventTypeSandboxDeleted    = "sandbox.deleted"
	EventTypeSandboxFailed     = "sandbox.failed"
	EventTypeSessionExpired    = "session.expired"
	EventTypeCodeExecuted      = "code.executed"
	EventTypeCodeFailed        = "code.failed"
	EventTypeFileUploaded      = "file.uploaded"
	EventTypeFileDownloaded    = "file.downloaded"
	EventTypeHealthCheckFailed = "health.failed"
)

// Webhook represents a webhook configuration.
type Webhook struct {
	ID           string            `json:"id"`
	URL          string            `json:"url"`
	Secret       string            `json:"secret,omitempty"`
	Events       []string          `json:"events"`
	Headers      map[string]string `json:"headers,omitempty"`
	Active       bool              `json:"active"`
	CreatedAt    time.Time         `json:"created_at"`
	UpdatedAt    time.Time         `json:"updated_at"`
	LastUsedAt   *time.Time        `json:"last_used_at,omitempty"`
	FailureCount int               `json:"failure_count,omitempty"`
	RetryConfig  RetryConfig       `json:"retry_config,omitempty"`
}

// RetryConfig configures webhook retry behavior.
type RetryConfig struct {
	MaxRetries  int           `json:"max_retries"`
	RetryDelay  time.Duration `json:"retry_delay"`
	MaxDelay    time.Duration `json:"max_delay"`
	BackoffRate float64       `json:"backoff_rate"`
}

// DefaultRetryConfig returns default retry configuration.
func DefaultRetryConfig() RetryConfig {
	return RetryConfig{
		MaxRetries:  3,
		RetryDelay:  1 * time.Second,
		MaxDelay:    5 * time.Minute,
		BackoffRate: 2.0,
	}
}

// WebhookStore defines the interface for webhook storage.
type WebhookStore interface {
	Create(webhook *Webhook) error
	Get(id string) (*Webhook, error)
	Update(webhook *Webhook) error
	Delete(id string) error
	List() ([]*Webhook, error)
	ListByEvent(eventType string) ([]*Webhook, error)
}

// Manager manages webhooks.
type Manager struct {
	store  WebhookStore
	client *http.Client
}

// NewManager creates a new webhook manager.
func NewManager(store WebhookStore) *Manager {
	return &Manager{
		store: store,
		client: &http.Client{
			Timeout: 30 * time.Second,
		},
	}
}

// Create creates a new webhook.
func (m *Manager) Create(req CreateWebhookRequest) (*Webhook, error) {
	// Validate URL
	if req.URL == "" {
		return nil, errors.New("URL is required")
	}
	if _, err := url.Parse(req.URL); err != nil {
		return nil, fmt.Errorf("invalid URL: %w", err)
	}

	// Validate events
	if len(req.Events) == 0 {
		return nil, errors.New("at least one event type is required")
	}

	webhook := &Webhook{
		ID:          uuid.New().String(),
		URL:         req.URL,
		Secret:      req.Secret,
		Events:      req.Events,
		Headers:     req.Headers,
		Active:      true,
		CreatedAt:   time.Now(),
		UpdatedAt:   time.Now(),
		RetryConfig: req.RetryConfig,
	}

	if webhook.RetryConfig.MaxRetries == 0 {
		webhook.RetryConfig = DefaultRetryConfig()
	}

	if err := m.store.Create(webhook); err != nil {
		return nil, fmt.Errorf("failed to create webhook: %w", err)
	}

	return webhook, nil
}

// CreateWebhookRequest represents a request to create a webhook.
type CreateWebhookRequest struct {
	URL         string            `json:"url" validate:"required,url"`
	Secret      string            `json:"secret,omitempty"`
	Events      []string          `json:"events" validate:"required,min=1"`
	Headers     map[string]string `json:"headers,omitempty"`
	RetryConfig RetryConfig       `json:"retry_config,omitempty"`
}

// Dispatch sends an event to all registered webhooks.
func (m *Manager) Dispatch(eventType string, payload *EventPayload) error {
	webhooks, err := m.store.ListByEvent(eventType)
	if err != nil {
		return fmt.Errorf("failed to list webhooks: %w", err)
	}

	event := &Event{
		ID:        uuid.New().String(),
		Type:      eventType,
		Timestamp: time.Now(),
	}

	payloadBytes, err := json.Marshal(payload)
	if err != nil {
		return fmt.Errorf("failed to marshal payload: %w", err)
	}
	event.Payload = payloadBytes

	// Dispatch asynchronously
	for _, webhook := range webhooks {
		if !webhook.Active {
			continue
		}
		go m.send(webhook, event)
	}

	return nil
