	c.JSON(http.StatusOK, gin.H{"webhooks": webhooks})
}

// GetWebhook handles getting a single webhook.
func (h *Handler) GetWebhook(c *gin.Context) {
	id := c.Param("id")
	webhook, err := h.manager.store.Get(id)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "webhook not found"})
		return
	}

	c.JSON(http.StatusOK, webhook)
}

// UpdateWebhookRequest represents a request to update a webhook.
type UpdateWebhookRequest struct {
	URL         string            `json:"url,omitempty"`
	Secret      string            `json:"secret,omitempty"`
	Events      []string          `json:"events,omitempty"`
	Headers     map[string]string `json:"headers,omitempty"`
	Active      *bool             `json:"active,omitempty"`
	RetryConfig *RetryConfig      `json:"retry_config,omitempty"`
}

// UpdateWebhook handles webhook updates.
func (h *Handler) UpdateWebhook(c *gin.Context) {
	id := c.Param("id")
	webhook, err := h.manager.store.Get(id)
	if err != nil {
		c.JSON(http.StatusNotFound, gin.H{"error": "webhook not found"})
		return
	}

	var req UpdateWebhookRequest
	if err := c.ShouldBindJSON(&req); err != nil {
		c.JSON(http.StatusBadRequest, gin.H{"error": err.Error()})
		return
	}

	if req.URL != "" {
		webhook.URL = req.URL
	}
	if req.Secret != "" {
		webhook.Secret = req.Secret
	}
	if len(req.Events) > 0 {
		webhook.Events = req.Events
	}
	if req.Headers != nil {
		webhook.Headers = req.Headers
	}
	if req.Active != nil {
		webhook.Active = *req.Active
	}
	if req.RetryConfig != nil {
		webhook.RetryConfig = *req.RetryConfig
	}

	webhook.UpdatedAt = time.Now()
	if err := h.manager.store.Update(webhook); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.JSON(http.StatusOK, webhook)
}

// DeleteWebhook handles webhook deletion.
func (h *Handler) DeleteWebhook(c *gin.Context) {
	id := c.Param("id")
	if err := h.manager.store.Delete(id); err != nil {
		c.JSON(http.StatusInternalServerError, gin.H{"error": err.Error()})
		return
	}

	c.Status(http.StatusNoContent)
}
